function initQuizSetup(){const n=document.querySelectorAll(".custom-dropdown");n.length!==0&&n.forEach(n=>{const r=n.querySelector(".btn-dropdown"),t=n.querySelector(".dropdown-hidden-input"),i=n.querySelectorAll(".dropdown-item"),u=r.querySelector(".selected-text");if(r&&t&&u){const f=t.value;i.forEach(n=>{n.getAttribute("data-value")===f&&n.classList.add("active")});i.forEach(n=>{n.addEventListener("click",r=>{r.preventDefault(),i.forEach(n=>n.classList.remove("active")),n.classList.add("active"),t.value=n.getAttribute("data-value"),u.innerText=n.innerText})})}})}document.readyState==="loading"?document.addEventListener("DOMContentLoaded",initQuizSetup):initQuizSetup();